#!/usr/bin/env node
/**
 * .github/scripts/generate-module-docs.js
 * Genera docs/modulos.md escaneando TSDoc en componentes/hooks/lib.
 */

const fs = require('fs');
const path = require('path');

const ROOT = path.resolve(__dirname, '../..');

function scanForFiles(dir, ext) {
  const results = [];
  if (!fs.existsSync(dir)) return results;
  const entries = fs.readdirSync(dir, { withFileTypes: true });
  for (const entry of entries) {
    const full = path.join(dir, entry.name);
    if (entry.isDirectory()) results.push(...scanForFiles(full, ext));
    else if (entry.name.endsWith(ext)) results.push(full);
  }
  return results;
}

function extractJsDoc(src) {
  const match = src.match(/\/\*\*([\s\S]*?)\*\//);
  if (!match) return '';
  return match[0]
    .replace(/^\/\*\*/, '').replace(/\*\/$/, '')
    .split('\n').map((l) => l.replace(/^\s*\*\s?/, '')).join('\n').trim();
}

function extractExports(src) {
  return [...src.matchAll(/export\s+(?:async\s+)?(?:function|const|class|interface|type)\s+(\w+)/g)]
    .map((m) => m[1]);
}

let content = '# Módulos y Componentes\n\n*Auto-generated by CI — do not edit manually*\n\n';

const sections = [
  { label: 'Componentes React', dir: 'src/components', ext: '.tsx' },
  { label: 'Hooks Personalizados', dir: 'src/hooks', ext: '.ts' },
  { label: 'Utilidades', dir: 'src/lib', ext: '.ts' },
  { label: 'Stores Zustand', dir: 'src/stores', ext: '.ts' },
];

for (const { label, dir, ext } of sections) {
  const fullDir = path.join(ROOT, dir);
  if (!fs.existsSync(fullDir)) continue;
  content += `## ${label}\n\n`;
  for (const file of scanForFiles(fullDir, ext)) {
    const rel = file.replace(ROOT + '/', '');
    const src = fs.readFileSync(file, 'utf8');
    const jsdoc = extractJsDoc(src);
    const exports = extractExports(src);
    if (exports.length > 0 || jsdoc) {
      content += `### \`${rel}\`\n`;
      if (jsdoc) content += `${jsdoc}\n`;
      if (exports.length > 0) content += `**Exports:** ${exports.join(', ')}\n`;
      content += '\n';
    }
  }
}

fs.writeFileSync(path.join(ROOT, 'docs/modulos.md'), content);
console.log('✅ docs/modulos.md generated');
